using json = nlohmann::json;
class Monitor1 {
public:
    void start() { running_=true; thread_=std::thread([this](){ while(running_){ check(); std::this_thread::sleep_for(std::chrono::seconds(interval_)); } }); }
    void stop() { running_=false; if(thread_.joinable()) thread_.join(); }
    void check() { int64_t now=std::chrono::duration_cast<std::chrono::milliseconds>(std::chrono::system_clock::now().time_since_epoch()).count(); checkCount_++; lastCheck_=now; }
    json getStatus() { json s;s[std::string("monitor")]=std::string("Monitor1");s[std::string("running")]=running_.load();s[std::string("checks")]=checkCount_.load();s[std::string("lastCheck")]=lastCheck_.load();return s; }
    void setInterval(int sec) { interval_=sec; }
    int64_t getCheckCount() const { return checkCount_.load(); }
private:
    std::atomic<bool> running_{false};
    std::atomic<int64_t> checkCount_{0},lastCheck_{0};
    int interval_=60;
    std::thread thread_;
};
